// Categorías únicas para filtros
export const categorias = ['Todas', ...new Set(posts.map(p => p.categoria))]

// Obtener post por slug
export function getPostBySlug(slug) {
  return posts.find(p => p.slug === slug) || null
}

// Obtener posts relacionados (misma categoría, excluyendo el actual)
export function getPostsRelacionados(slug, limite = 3) {
  const post = getPostBySlug(slug)
  if (!post) return []
  return posts.filter(p => p.slug !== slug && p.categoria === post.categoria).slice(0, limite)
}
